    UploadLeadFile:function() {
        this.isLoading=true;
        var vm=this;
        const formdata=new FormData();
        formdata.append("file",vm.file);
        if(vm.file!=undefined && vm.file!=null){
        DataService.ImportContactsPost(formdata).then(function(response) { 
            var data=response.data;     
                    if (data.Status == 0) {
                        vm.filepath = data.Msg;
                        setTimeout(function () { vm.loadExcelHeader(data.Msg); }, 1000);
                        setTimeout(function () { vm.loadTableHeader(); }, 2000);
                        vm.isLoading=false;
                        vm.isUploadedExcel=true;
                    }else if (data.Status == 1)
                    {
                        vm.ShowAlert(vm.$t("IsNotValidFileUpload"), "warning", true, vm.$t("Alert"));
                        vm.isLoading=false;
                    }
                    else {
                        vm.isLoading=false;
                        vm.ShowAlert(data.Msg, "warning", true, vm.$t("Alert"));
                    }
                });
            }
            else{
                vm.isLoading=false;
                vm.ShowAlert(vm.$t("Please upload valid excel file."), "warning", true, vm.$t("Alert"));
            }
