    loadExcelHeader:function(filepath){
        var vm=this;
        vm.isLoading=true;
        var param=`filepath=${filepath}&excelFileName=${vm.excelFileName}`;
        DataService.GetContactExcelColumn(param)
        .then(function(response) {
           var data=response.data;
            vm.isLoading=false;
            if (data.length != undefined) {
                   var select = $("#ddlExcelColumn");
                    select.empty();
                    $.each(data, function (index, itemData) {
                        $('#hdnBatchId').val(itemData.batch_id);
                        $("#ddlExcelColumn").append("<option value='" + itemData.column_Name + "'Column_length='" + itemData.column_Length + "'Data_Type='" + itemData.data_Type + "' >" + itemData.column_Name + "</option>");
                    });
                }
        })
    },
    loadTableHeader:function(){
        var vm=this;
        vm.isLoading=true;   
        var param="submodule=CRM_LEADS&batchid=''"; 
        DataService.GetContactTableColumn(param)
        .then(function(response) {
            var data=response.data;
            vm.isLoading=false;
            if (data.length != undefined) {             
                   var select = $("#ddlTableColumn");
                    select.empty();
                    data.sort((a, b) => {
                        if (a.is_Required) {
                            return -1
                        } else {
                            return 1
                        }
                    });
                    $.each(data, function (index, itemData) {
                        var data = '';
                        if (itemData.is_Required && itemData.column_Name != 'existing_client_id') {
                            vm.allrequiredcol = vm.allrequiredcol + itemData.column_Name +',';
                            data = vm.GetLocalizedValue(itemData.column_Name, itemData.display_Name) + '*'
                        }
