            var Tableoptions = "";
            $(".norecord").addClass("d-none");
            for (var i = 0; i < totalRecords; i++) {               
                $(table).clone().attr({ 'crtrwid': rownumber }).removeClass("d-none").addClass("visible")
                    .find("input,a,select,div").each(function () {
                        $(this).attr({
                            'id': function (_, id) {return id + "" + rownumber;},
                            'name': function (_, name) {return name + "" + rownumber;},
                            'value': function (_, value) { return value; }
                        });
                        $(this).removeClass("d-none");
                    }).end().appendTo("table#tblbulklead");
                Exceloptions = $('#ddlExcelColumn').children('option').clone();
                Tableoptions = $('#ddlTableColumn').children('option').clone();
                $("table#tblbulklead tr.visible td select[id='ddlTableColumn" + rownumber + "']").remove();
                $("table#tblbulklead tr.visible td select[name='TableColumns" + rownumber + "']").attr('id', 'ddlTableColumn' + rownumber);
                //$("table#tblbulklead tr.visible td select[name='TableColumns" + rownumber + "']").attr('onclick', 'CheckDuplicateTableRecord(ddlTableColumn' + rownumber + ')');

                $("table#tblbulklead tr.visible td select[name='TableColumns" + rownumber + "']")
                .on("change", function() { 
                    CheckDuplicateTableRecord('ddlTableColumn' + rownumber);
                });

                $("table#tblbulklead tr.visible td select[name='TableColumns" + rownumber + "']").append(Tableoptions);
                $("table#tblbulklead tr.visible td select[id='ddlExcelColumn" + rownumber + "']").remove();
                $("table#tblbulklead tr.visible td select[name='ExcelColumns" + rownumber + "']").attr('id', 'ddlExcelColumn' + rownumber);
                //$("table#tblbulklead tr.visible td select[name='ExcelColumns" + rownumber + "']").attr('onclick', 'CheckDuplicateExcelRecord(ddlExcelColumn' + rownumber + ')');

                $("table#tblbulklead tr.visible td select[name='ExcelColumns" + rownumber + "']")
                .on("change", function() { 
                    CheckDuplicateExcelRecord('ddlExcelColumn' + rownumber);
                });

                $("table#tblbulklead tr.visible td select[name='ExcelColumns" + rownumber + "']").append(Exceloptions);
                  
                if (Exceloptions.length > i) {
                    var tc_datatype = $("#ddlTableColumn" + rownumber + " option[value='" + Exceloptions[i].value + "']").attr('data_type');
                    var ex_datatype = $("#ddlExcelColumn" + rownumber + " option[value='" + Exceloptions[i].value + "']").attr('data_type');
                    var tc_Value = $("#ddlTableColumn" + rownumber + " option[value='" + Exceloptions[i].value + "']").attr('value');
                    var ex_Value = $("#ddlExcelColumn" + rownumber + " option[value='" + Exceloptions[i].value + "']").attr('value');                   
                    if (tc_datatype != undefined && ex_datatype != undefined) {                       
                        if (tc_Value.toLowerCase() == ex_Value.toLowerCase()) {
                            $("#ddlTableColumn" + rownumber + " option[value='" + Exceloptions[i].value + "']").attr('selected', 'selected');
                            $("#ddlExcelColumn" + rownumber + " option[value='" + Exceloptions[i].value + "']").attr('selected', 'selected');
                        }                       
                    }

                    //console.log(`ExcelOption=${Exceloptions[i].value} tc_Value=${tc_Value}  - ex_Value=${ex_Value}`)

                }               
                rownumber++;
            }
            $("table#tblbulklead tr.visible[crtrwid ='" + 1001 + "']").removeClass("visible").addClass("d-none");
            vm.isLoading=false;
