    SaveLeadFile() {
        try {
            var vm=this;
            $(savebtn).addClass("disabled");
            var xml = "<leadentries>\n";
            var isError = false;
            var valid = '';
            var rowid = 0;
            var saveFlag = false;
            this.isLoading=true;
            this.requiredcol= this.allrequiredcol;
            var array = this.requiredcol.split(",");
            for (let index of array) {
                $("table#tblbulklead tr.visible").each(function () {
                    rowid = $(this).attr("crtrwid");               
                    if (!$(this).hasClass('alert-success')) {
                        if (index == $(this).find('#ddlTableColumn' + rowid).val()) {
                            vm.requiredcol = vm.requiredcol.replace(new RegExp(index + ',?'), '');                       
                        }
                    }
                });
            }
            if (vm.requiredcol.length > 0) {
                isError = true;
                $('#lbl_ErrorForColumn').parent().removeClass('d-none');
                let formattedString = vm.requiredcol.replace(/,/g, ', ');
                let items = formattedString.split(',');
                items = items.map(item => item.trim()).filter(item => item !== "" && item !== null);
                let listHtml = '<div style="padding-left: 708px;text-align: left">';
                items.forEach((item, index) => {
                    listHtml += `<div>${index + 1}. ${item}</div>`;
                });
                listHtml += '</div>';
                $('#lbl_ErrorForColumn').html(vm.$t('SelectAllMandatory') + ' <br> ' + listHtml);
                $(document).scrollTop(0);
                vm.isLoading = false;
            }
            else {
                $('#lbl_ErrorForColumn').html('');
                $('#lbl_ErrorForColumn').parent().addClass('d-none');
            $("table#tblbulklead tr.visible").each(function () {
                rowid = $(this).attr("crtrwid");
                $("table#tblbulklead tr.visible[crtrwid ='" + rowid + "']").removeClass('alert-warning')
                if (!$(this).hasClass('alert-success') && $(this).find('#ddlTableColumn' + rowid).val()!="") {
                    $("table#tblbulklead tr.visible").each(function () {
                        rowid = $(this).attr("crtrwid");                   
                        if (($(this).find('#ddlTableColumn' + rowid).val() != "") && ($(this).find('#ddlExcelColumn' + rowid).val() == "")) {
                            valid += CheckRequiredR("ddlExcelColumn" + rowid, vm.$t("PleaseSelectAnyRecordsForFurther"), "invalid-feedback");
                        }
                    });
                    if (valid != '') {
                        isError = true;
                    }
                    if (isError) {
                        $('#lbl_ErrorForColumn').parent().removeClass('d-none');
                        $('#lbl_ErrorForColumn').html(vm.$t('SelectAllMandatory'));
                        $(document).scrollTop(0);
                        vm.isLoading=false;
                        return false;
                    } else {
                        $('#lbl_ErrorForColumn').html('');
                        $('#lbl_ErrorForColumn').parent().addClass('d-none');
                        rowid = $(this).attr("crtrwid");
                        var original_column_name = $(this).find('#ddlTableColumn' + rowid).val();
                        var column_name = $(this).find('#ddlTableColumn' + rowid).val();
                        var data_type = $(this).find('#ddlTableColumn' + rowid).find(":selected").attr('data_type');
                        var custom_field_id = $(this).find('#ddlTableColumn' + rowid).find(":selected").attr('Custom_Field_Id');
                        var look_up = $(this).find('#ddlTableColumn' + rowid).find(":selected").attr('Picklist_Options');
                        var excel_column_name = $(this).find('#ddlExcelColumn' + rowid).val();
                        var excel_data_type = $('#ddlExcelColumn' + rowid).find(":selected").attr('data_type');

                        if (look_up == null) {
                            look_up = '';
                        }
                        if (column_name != undefined) {
                            saveFlag = true;
                            xml += "\n<lead>" +
                                "\n\t<batch_id>" + $('#hdnBatchId').val() + "</batch_id>" +
                                "\n\t<row_id>" + rowid + "</row_id>" +
                                "\n\t<original_column_name>" + original_column_name + '_' + look_up + "</original_column_name>" +
                                "\n\t<column_name>" + column_name + "</column_name>" +
                                "\n\t<data_type>" + data_type.toLowerCase() + "</data_type>" +
                                "\n\t<custom_field_id>" + custom_field_id + "</custom_field_id>" +
                                "\n\t<excel_column_name>" + excel_column_name.trim().replace(/[\r\n]+/gm, '_').replace(/[^a-zA-Z0-9_ \s]/gi, '').replace(/[-\s]/g, '_') + "</excel_column_name>" +
                                "\n\t<excel_data_type>" + excel_data_type.toLowerCase() + "</excel_data_type>" +
                                "\n</lead>\n";
                        }
                    }
                }
            });
            xml += "\n</leadentries>\n";
            if (!isError && saveFlag) {
                //console.log({ xmltrackentries: xml, batch_id: $('#hdnBatchId').val() });
                var postJSON = {
                    xmltrackentries: xml,
                    batch_id: $('#hdnBatchId').val(),
                    callingSource:"Lead"
                };
                var objectPostString = JSON.stringify(postJSON);
            DataService.BulkUploadContact(objectPostString)
            .then(function (response) {
                    vm.isLoading=false;
                    var data=response.data;
                if (data.length != undefined) {            
                        vm.$router.push({
                            name: 'CRMLeadImportDetails', params: {
                                subModuleCode: 'CRM_CONTACTS',
                                batchid:postJSON.batch_id
                            }
                        });                 
                        }
                
                });
            }
        }
        } catch (error) {
            vm.isLoading=false;
            //alert(error);
        }
   }
}
}
window.CheckDuplicateTableRecord = function(ctrlid) {
        var objarr = [];
        var flag = true;
        $("table#tblbulklead tr#trdata").each(function () {
            var ddlval = $(this).find("td").eq(0).find("select option:selected").text();
            objarr.push(ddlval);
        }); //end of each
        var controlid;
        var dupid2;
        var dupid;
        var indexno = 1002;
         flag = false;
        var i; var j;
        for (i = 1; i < objarr.length; i++) {
            controlid = '#ddlTableColumn' + indexno;
        
            for (j = i + 1; j < objarr.length; j++) {
           
                if (objarr[i] == objarr[j] && objarr[i] != "Select Column") {
                    flag = true;
                   
                    dupid = controlid;
                    dupid2 = '#ddlTableColumn' + (1002 + (j - 1));
                    break;
                }
            }
            if (flag) {
                break;
            }
            $(controlid).removeClass('border border-danger');
            $(savebtn).removeClass("disabled");
            indexno++;
        }
        if (flag) {
            $(dupid).addClass('border border-danger');
            $(dupid2).addClass('border border-danger');
            $(savebtn).addClass("disabled");
        }
        flag = false;
        $("table#tblbulklead tr#trdata").each(function () {
           if ($(this).find("td").eq(1).find("select").hasClass("border-danger")) {
                $(savebtn).addClass("disabled");
            }
        }); 
    }
window.CheckDuplicateExcelRecord = function(ctrlid) {
    var objarr = [];
    var flag = true;
    $("table#tblbulklead tr#trdata").each(function () {
        var ddlval = $(this).find("td").eq(1).find("select option:selected").text();
        objarr.push(ddlval);
    }); 
    var controlid;
    var dupid2;
    var dupid;
    var indexno = 1002;
    var flag = false;
    var i; var j;
    for (i = 1; i < objarr.length; i++) {
        controlid = '#ddlExcelColumn' + indexno;
  
        for (j = i + 1; j < objarr.length; j++) {
         
            if (objarr[i] == objarr[j] && objarr[i] != "Select Column") {
                flag = true;
               
                dupid = controlid;
                dupid2 = '#ddlExcelColumn' + (1002 + (j - 1));
                break;
            }
        }
        if (flag) {
            break;
        }
        $(controlid).removeClass('border border-danger');
        $(savebtn).removeClass("disabled");
        indexno++;
    }
    if (flag) {
        $(dupid).addClass('border border-danger');
        $(dupid2).addClass('border border-danger');
        $(savebtn).addClass("disabled");
    }
    flag = false;
    $("table#tblbulklead tr#trdata").each(function () {
   
        if ($(this).find("td").eq(0).find("select").hasClass("border-danger")) {
            $(savebtn).addClass("disabled");
        }
    });     
}
function CheckRequiredR(el, msg, cssClass) {
    var vm = this;
    var el1 = $(el);
    el1 = el1.length > 0 ? el1 : $("#" + el);
    var spn = $(el1).attr("name");
    $(el1).removeClass("is-invalid");
    var errorCssclass = cssClass;
    if (spn != undefined) {
        if (cssClass == undefined) {
            cssClass = 'invalid-feedback';
        }
        $("span[data-valmsg-for='" + spn + "']").removeClass(cssClass).addClass("invalid-feedback").css("display", "block").html(" ");
        //$(".invalid-feedback").css("display", "block");
    }

    var val = $.trim($(el1).val());
    if (val.length <= 0) {
        if (!msg)
            if ($(el1).attr("data-val-required")) msg = $(el1).attr("data-val-required");
            else if (vm.$t(spn)) msg = String.Format(vm.$t("Required"),
            vm.$t(spn));
        if (el == "ProjectId") {
            msg = vm.$t("ProjectName") + " " + vm.$t("Required");
            msg = String(msg).replace("{0}", "");
        }
        ShowError(el1, msg, errorCssclass, "R");
        return "no";
    }
    if (!potentialDangerous(val)) {
        ShowError(el1, msg == "" ? "" : vm.$t("InvalidInput"), cssClass);
        return "no";
    }
    return "";
}
function ShowError(el, msg, cssClass, isFor) {
    if (cssClass) {
        if (cssClass.length <= 0) cssClass = "field-validation-error";
    } else cssClass = "field-validation-error";
    if (isFor == "R") {
        cssClass = "invalid-feedback";
        $(el).addClass("is-invalid");
    }
    else {
        $(el).addClass("input-validation-error");
    } 
    var spn;
    var newspn;
    var spantag;
    if (msg) {
        spn = $(el).attr("name");
        if (spn != undefined) {
            newspn = spn;
            if (spn.indexOf(".") > -1) spn = spn.replace(".", "\\.");
            spantag = "span[data-valmsg-for='" + spn + "']";
            if ($(spantag).length > 0) $(spantag).removeClass("field-validation-valid").addClass(cssClass).html(msg);
            else {
                if (isFor == "R") {
                    $(el).parent().append("<span class='invalid-feedback' data-valmsg-for='" + newspn + "' >" + msg + " </span>");
                }
                else {
                    $(el).parent().append("<span class='field-validation-error textalignleft text-danger' data-valmsg-for='" + newspn + "' >" + msg + " </span>");
                }
            }
        }
    } else {
        if ($(el).attr("data-val-regex")) {
            msg = $(el).attr("data-val-regex");
            spn = $(el).attr("name");
            if (spn != undefined) {
                newspn = spn;
                if (spn.indexOf(".") > -1) spn = spn.replace(".", "\\.");
                spantag = "span[data-valmsg-for='" + spn + "']";
                if ($(spantag).length > 0) $(spantag).removeClass("field-validation-valid").addClass(cssClass).html(msg);
                else {
                    if (isFor == "R") {
                        $(el).parent().append("<span class='invalid-feedback' data-valmsg-for='" + newspn + "' >" + msg + " </span>");
                    }
                    else {
                        $(el).parent().append("<span class='field-validation-error textalignleft text-danger' data-valmsg-for='" + newspn + "' >" + msg + " </span>");
                    }
                }
            }
        }
    }
}
</script>