<template>
    <div>
        <loader :is-visible="isLoading"></loader>
       
        <tg-list :IsShowAction="false" ModuleName="CRM" :SubModuleCode="subModuleCode" IdentityColumn="id"
            :listType="['List']" :ListData="ListData" ref="tgList" :HeaderData="Headers"
            :HeaderButtons="false" :TotalRecords="TotalRecords" :IsSearchFieldsOnTop="false" :SearchFields="false"
            :widgets="[]" :RenderRowActionMethod="renderActions" :ListDataCallBackFunction="FetchData" :LegendArray="[]"
            :IsFilterApplied="false" :SortExp="SortExp" :SortBy="SortBy"
            :CurrentPageNumber="PageNumber" v-on:LeftsearchButtonClick="leftCommonSearch"
            v-on:PagerButtonClick="pagerMethod" :NorecordfoundText="$t('NoRecordfound')"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:ActionButtonClick="actionButtonClick"
            v-on:SortdataButtonClick="sortdata" :showCheckBox="false">
            <template v-slot:slotdata="{ data }"> 
                <template v-if="data.column.COLUMN_NAME == 'import_status'">
                    <a class="inactive-disabled" >
                    <span :class="['btn text-center text-white d-block',(data.row.import_status=='Unfinished' ? 'bg-secondary' : 'bg-success')]">
                        {{ data.row[data.column.COLUMN_NAME] }}
                    </span>
                </a>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'statistics'">
                    <a v-on:click="showBatchStats(data.row.batch_id)" href="javascript:;" :class="{'btn btn-info btnshowstats':true, 'disabled':data.row.import_status == 'Unfinished'}">{{ $t('ShowStats') }}</a>
                    <!-- <a v-on:click="showBatchStats(data.row.batch_id)" href="javascript:;" :class="{'btn btn-info btnshowstats':true}">{{ $t('ShowStats') }}</a> -->
                </template>
                <template v-if="data.column.COLUMN_NAME == 'action'">
                    <span v-if="data.row.import_status == 'Unfinished'">
                        <a href="javascript:;" class="btn btn-success" @click="UploadPendingExcel(data.row)">{{$t('Continue')}}</a>
                        <a href="javascript:;" class="btn btn-secondary ml-2" @click="deleteBatch(data.row)" >{{ $t('Discard') }}</a>
                    </span>
                    <span v-else>
                        <a href="javascript:;" @click="deleteBatch(data.row)" ><em class="fa fa-trash text-danger font-24"></em></a>
                    </span>
                </template>
            </template>
        </tg-list>
        <modalExcelBatchStats v-if="isShowBatchStats" @close="isShowBatchStats = false" :batchId="batchId" :subModuleCode="subModuleCode"></modalExcelBatchStats>
    </div>
</template>
<script>
import DataService from '../../services/DataService';
import modalExcelBatchStats from './Modal/modalExcelBatchStats.vue';

export default {
    props: {
        subModuleCode: {
            type: String,
            required: true
        }
  },
  components: {
        modalExcelBatchStats,
    },
    data: function () {
        return {
            SortExp: '',
            SortBy: '',
            isLoading: false,
            ListData: [],
            Headers: [
                {
                    COLUMN_NAME: 'file_name',
                    DATA_TYPE: "string",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('FileName'),
                    DISPLAY_ORDER: 1,
                },
                {
                    COLUMN_NAME: 'created_at',
                    DATA_TYPE: "datetime",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('DateAndTime'),
                    DISPLAY_ORDER: 2,
                },
                {
                    COLUMN_NAME: 'user_name',
                    DATA_TYPE: "string",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('UserName'),
                    DISPLAY_ORDER: 3,
                },
                {
                    COLUMN_NAME: 'import_status',
                    DATA_TYPE: "string",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('Status'),
                    DISPLAY_ORDER: 4,
                    settings : {
                        isInSlot: true
                    }
                },
                {
                    COLUMN_NAME: 'statistics',
                    DATA_TYPE: "string",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('Statistics'),
                    DISPLAY_ORDER: 5,
                    settings : {
                        isInSlot: true
                    }
                },
                {
                    COLUMN_NAME: 'action',
                    DATA_TYPE: "string",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('Action'),
                    DISPLAY_ORDER: 6,
                    settings : {
                        isInSlot: true
                    }
                }
            ],
            TotalRecords: 0,
            PageNumber: 1,
            PageSize: 10,
            batchId:null,
            isShowBatchStats: false,
        }
    },
    created: async function () {
        await this.FetchData();
    },

    methods: {
        FetchData: async function () {
            var vm = this;
            var param = `subModuleCode=${vm.subModuleCode}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&pageNum=${vm.PageNumber}&pageSize=${vm.PageSize}&searchCondition=`;
            await DataService.GetImportedBatchList(param).then(response => {
                    if(response.data && response.data.length > 0) {
                        vm.ListData = response.data;
                        vm.TotalRecords = response.data[0].total_records;
                    } else {
                        vm.ListData = [];
                        vm.TotalRecords = 0;
                    }
                })
            vm.isLoading = false;
        },

        sortdata: function (s) {            
            var SortDir = "sort tb_headerSortDown";
            this.SortBy = s;
            if (s === this.SortBy) {
                if (this.SortExp == "") {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
                else if (this.SortExp == "ASC") {
                    this.SortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                }
                else {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }
            this.FetchData();
            $("#" + s + '  span:first-child').attr("class", SortDir);
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        showBatchStats(batchId) {
            this.batchId = batchId;
            this.isShowBatchStats = true;

        },
       async deleteBatch(row){
            var vm = this;
            vm.confirmR(this.$t("ConfirmDelete"), this.$t("Delete"), this.$t("Batch"), async function () {
                vm.isLoading = true;
                var param = `batchId=${row.batch_id}`;
               await DataService.DeletBatchRow(param).then(function (response) {
                    if (response.data && response.data[0].Value) {
                        if(response.data[0].Value.toLowerCase()=='success'){
                            vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('Batch')]), 'success', true, vm.$t("Alert"));
                            vm.FetchData();
                            vm.isLoading = false;
                        }
                        else {
                            vm.ShowAlert(vm.$t('DeletedError', [vm.$t('Batch')]), 'failure', true, vm.$t("Alert"));
                        }
                    }
                    else {
                        vm.ShowAlert(vm.$t('DeletedError', [vm.$t('Batch')]), 'failure', true, vm.$t("Alert"));
                    }
                    vm.isLoading = false;
                });
            });
        },
        leftCommonSearch() { },
        renderActions() { },
        commonHeaderButtonClick() { },
        actionButtonClick() { },
       async UploadPendingExcel(row){
            var vm = this;
            vm.isLoading = true;
            var param = `BatchId=${row.batch_id}&ModuleCode=CRM&SubModuleCode=CRM_LEADS&IsAction=Add&UpdateField= `;
           await DataService.SaveImportleadData(param).then(function (response) {
                if (response.data == "ADD DATA SUCCESSFULLY!") {
                    vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Leads')]), 'success', true, vm.$t("Alert"));
                    vm.FetchData();
                    vm.isLoading = false;
                }
                else {
                    vm.ShowAlert(vm.$t('AddedError', [vm.$t('Lead')]), 'failure', true, vm.$t("Alert"));
                }
                vm.isLoading = false;
            });
        }
    }
    }
</script>