<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <div class="col-lg-12 p-0 float-left">
            <div class="listing mt-2">
                <div class="table-responsive">
                    <table id="tblbulklead" class="table table-bordered dt-responsive nowrap m-0" style="width:100%;"
                        aria-describedby="importlead">
                        <thead class="thead-bg">
                            <tr>
                                <th style="width: 10px;">
                                    <span class="d-inline-block" style="width: 130px; text-align: center;">
                                        {{ $t('S.No') }}
                                        <span class="d-inline-block"><span class="text-danger"></span></span>
                                    </span>
                                </th>
                                <th>
                                    <span class="d-inline-block" style="min-width: 138px;">
                                        {{ $t('TableColumn') }}
                                        <span class="d-inline-block"><span class="text-danger">*</span></span>
                                    </span>
                                </th>
                                <th>
                                    <span class="d-inline-block" style="min-width: 138px;">
                                        {{ $t('ExcelColumn') }}
                                    </span>
                                </th>
                                <th v-if="GetUserInfo.UserType == 'CA'">
                                    <span>{{ $t('Action') }}</span>
                                </th>
                            </tr>
                        </thead>
                        <tbody>
                            <tr v-for="(row, index) in tableColumns" :key="index">
                                <!-- S.no -->
                                <td style="text-align: center;">
                                    {{ index + 1 }}
                                </td>
                                <!-- Table Column Dropdown -->
                                <td>
                                    <select class="form-control" v-model="selectedTableColumns[index]"
                                        @change="validateDuplicates" :class="{
                                            'border-red': selectedTableColumns[index] &&
                                                duplicateTableColumns.includes(selectedTableColumns[index])
                                        }">
                                        <option value="">{{ $t('Select') }} {{ $t('Column') }}</option>
                                        <option v-for="(column, colIndex) in sortedTableColumns" :key="colIndex"
                                            :value="column.column_Name">
                                            {{ $t(column.display_Name) }}
                                            <span v-if="column.is_Required" class="text-danger">*
                                            </span>
                                        </option>
                                    </select>
                                </td>
                                <!-- Excel Column Dropdown -->
                                <td style="overflow: visible!important;">
                                    <Multiselect v-model="selectedExcelColumns[index]" :options="excelColumns"
                                        :multiple="false" :searchable="true" :close-on-select="true"
                                        :clear-on-select="false" :preserve-search="true" label="column_Name"
                                        track-by="column_Name" :class="{
                                            'border-red': selectedExcelColumns[index] && duplicateExcelColumns.includes(selectedExcelColumns[index].column_Name)
                                        }" @input="validateDuplicates" />

                                    <!-- <select class="form-control" v-model="selectedExcelColumns[index]"
                                        @change="validateDuplicates" :class="{
                                            'border-red': selectedExcelColumns[index] &&
                                                duplicateExcelColumns.includes(selectedExcelColumns[index])
                                        }">
                                        <option value="">{{ $t('Select') }} {{ $t('Column') }}</option>
                                        <option v-for="(column, colIndex) in excelColumns" :key="colIndex"
                                            :value="column.column_Name">
                                            {{ column.column_Name }}
                                        </option>
                                    </select> -->
                                </td>
                                <td v-if="GetUserInfo.UserType == 'CA'">
                                    <a href="javascript:;" class="btn btn-success" @click="addCustomField(index)">
                                        {{ $t('AddCustomField') }}
                                    </a>
                                </td>
                            </tr>
                        </tbody>

                    </table>
                </div>
            </div>
            <div>
                <!-- class="col-12 mt-3 p-0" -->
                <div class="row flex-row-reverse">
                    <div class="col-lg-6 text-right">
                        <a href="/CRM/ImportLeadsNew" @click="BackToUpload" :title="$t('Back')"
                            :class="{ 'btn btn-secondary my-2 mr-2': true }">
                            <em class="fa fa-angle-double-left mr-2" aria-hidden="true"></em> {{ $t('Back') }}
                        </a>
                        <a href="javascript:void(0);" @click="createMultiRows" :title="$t('Next')"
                            :class="{ 'btn btn-primary my-2 mr-2': true }">
                            {{ $t('Next') }} <em class="fa fa-angle-double-right mr-2" aria-hidden="true"></em>
                        </a>

                    </div>
                    <div class="col-lg-6">
                        <div class="py-2">
                            <span class="text-danger">
                                <small class="text-danger">{{ $t('MandatoryString') }}</small>
                            </span>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <modalAddCustomField v-if="isShowAddCustomField" :newCustomField="newCustomField"></modalAddCustomField>
    </section>
</template>
<script>
import DataService from '../../services/DataService';
import modalAddCustomField from './Modal/modalAddCustomField.vue';
export default {
    name: 'ExcelColumnBind',
    props: {
        excelColumns: {
            type: Array,
            required: true
        },
        tableColumns: {
            type: Array,
            required: true
        }

    },
    components: {
        modalAddCustomField
    },
    watch: {
        // Watch for changes in excelColumns prop
        excelColumns(newValue) {
            console.log('excelColumns changed:', newValue);
            this.initializeSelections();
            // Perform actions when excelColumns changes
            // For example, update localState or trigger another method
        },
        // Watch for changes in tableColumns prop
        tableColumns(newValue) {
            console.log('tableColumns changed:', newValue);
            this.initializeSelections();
            // Perform actions when tableColumns changes
        }
    },
    data() {
        return {
            isLoading: false,
            selectedTableColumns: [],
            selectedExcelColumns: [],
            MatchingColumns: [],
            MatchingtableColumns: [],
            Btach_Id: '',
            isShowAddCustomField: false,
            sortedTableColumns: [],
            newCustomField: null,
            duplicateTableColumns: [],
            duplicateExcelColumns: [],
        }
    },
    mounted() {
        this.initializeSelections();
    },
    created() {

        this.sortedColumns(this.tableColumns);
        console.log("excelColumns", this.excelColumns);
        console.log("tableColumns", this.tableColumns);

    },
    methods: {
        BackToUpload() {
            this.$parent.isShowUploadExcelLead = true;
            this.$parent.isShowExcelColumnBind = false;
        },
        initializeSelections() {
            this.selectedTableColumns = this.tableColumns.map(col => col.column_Name);

            this.selectedExcelColumns = this.tableColumns.map(tc => {
                const translated = this.$t(tc.display_Name, tc.column_Name);
                const match = this.excelColumns.find(ec =>
                    ec.column_Name.toLowerCase() === translated.toLowerCase()
                );
                return match || null;
            });
        },

        validateDuplicates() {
            const duplicates = (arr) => {
                const counts = {};
                const dups = [];
                arr.forEach(val => {
                    const name = val?.column_Name;
                    if (name) {
                        counts[name] = (counts[name] || 0) + 1;
                        if (counts[name] === 2) dups.push(name);
                    }
                });
                return dups;
            };

            this.duplicateTableColumns = duplicates(this.tableColumns);
            this.duplicateExcelColumns = duplicates(this.selectedExcelColumns);


            if (this.duplicateTableColumns.length > 0 || this.duplicateExcelColumns.length > 0) {
                let message = '';
                if (this.duplicateTableColumns.length > 0) {
                    message += `Duplicate Table Columns: ${this.duplicateTableColumns.join(', ')}\n`;
                }
                if (this.duplicateExcelColumns.length > 0) {
                    message += `Duplicate Excel Columns: ${this.duplicateExcelColumns.join(', ')}`;
                }
                this.ShowAlert(message, "warning", this.$t('Alert'));
                return false;
            }
            return true;
        },
        sortedColumns(columns) {
            // First, filter required columns and then concatenate with non-required columns
            const requiredColumns = columns.filter(col => col.is_Required);
            const nonRequiredColumns = columns.filter(col => !col.is_Required);

            // Return required columns first, followed by non-required columns
            this.sortedTableColumns = [...requiredColumns, ...nonRequiredColumns];
        },
        createMultiRows() {
            var vm = this;
            vm.showSaveButton = true;

            // Create MatchingtableColumns by adding excel_Column_Name from selectedExcelColumns based on index
            vm.MatchingtableColumns = vm.tableColumns.map((col, index) => {
                const excelCol = vm.selectedExcelColumns[index];
                if (excelCol) {
                    return {
                        ...col,
                        // Make sure to assign the correct string value for excel_column_name
                        excel_Column_Name: excelCol.column_Name // <-- Make sure to get the specific value, not the whole object
                    };
                }
                return null; // skip if no excelCol at this index
            }).filter(col => col !== null); // remove nulls

            // Grab batch_id from first excel column
            vm.Btach_Id = vm.excelColumns[0].batch_id;

            // Ensure Batch ID exists
            if (!vm.Btach_Id) {
                vm.ShowAlert(vm.$t('BatchIdMissing'), "failure", vm.$t('Alert'));
                return;
            }

            const requiredColumns = vm.tableColumns.filter(col => col.is_Required);

            // Find missing required fields
            const missingFields = requiredColumns.filter(reqCol => {
                return !vm.MatchingtableColumns.find(matchCol => matchCol.column_Name === reqCol.column_Name);
            });

            if (vm.validateDuplicates()) {
                if (missingFields.length === 0) {
                    const incompleteFields = vm.MatchingtableColumns.filter(col => !col.excel_Column_Name);
                    if (incompleteFields.length === 0) {
                        vm.Next();
                    } else {
                        const incompleteFieldNames = incompleteFields.map(f => f.column_Name).join(', ');
                        vm.ShowAlert(
                            `Some columns are missing mapping: ${incompleteFieldNames}`,
                            "warning",
                            vm.$t('Alert')
                        );
                    }
                } else {
                    const missingFieldNames = missingFields.map(f => vm.$t(f.display_Name) || vm.$t(f.column_Name)).join(', ');
                    vm.ShowAlert(
                        `Please map all mandatory fields. Missing: ${missingFieldNames}`,
                        "warning",
                        vm.$t('Alert')
                    );
                }
            }
        },

        async Next() {

            var vm = this;
            vm.isLoading = true;
            var rowid = 1002;

            var xml = "<leadentries>\n";

            vm.MatchingtableColumns.forEach(element => {


                xml += "\n<lead>" +
                    "\n\t<batch_id>" + vm.Btach_Id + "</batch_id>" +
                    "\n\t<row_id>" + rowid + "</row_id>" +
                    "\n\t<original_column_name>" + element.column_Name + '_' + element.picklist_Options + "</original_column_name>" +
                    "\n\t<column_name>" + element.column_Name + "</column_name>" +
                    "\n\t<data_type>" + element.data_Type.toLowerCase() + "</data_type>" +
                    "\n\t<custom_field_id>" + element.custom_Field_Id + "</custom_field_id>" +
                    "\n\t<excel_column_name>" + element.excel_Column_Name + "</excel_column_name>" +
                    "\n\t<excel_data_type>" + element.data_Type.toLowerCase() + "</excel_data_type>" +
                    "\n</lead>\n";

                rowid++;

            });

            xml += "\n</leadentries>\n";

            var postJSON = {
                xmltrackentries: xml,
                batch_id: vm.Btach_Id,
                callingSource: "Lead"
            };

            var objectPostString = JSON.stringify(postJSON);
            await DataService.BulkUploadContact(objectPostString).then(function (response) {
                vm.isLoading = false;
                var data = response.data;
                if (data.length != undefined) {
                    vm.$emit('checkValidation');
                    vm.isLoading = false;
                }
                else {
                    vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", vm.$t('Alert'));
                    vm.isLoading = false;
                }
            });
        },
        addCustomField(index) {
            var vm = this;
            vm.newCustomField = vm.excelColumns.filter(x => x.column_Name == vm.selectedExcelColumns[index]);
            if (!vm.newCustomField) {
                vm.ShowAlert(vm.$t("Please select excel column, which you want to create in table."), "warning", vm.$t('Alert'));
                return;
            } else {
                vm.isShowAddCustomField = true;
            }
        },
        async closeCustomField() {
            var vm = this;
            await vm.loadTableHeader();
            vm.initializeSelections();
            vm.sortedColumns(vm.tableColumns);
            vm.isShowAddCustomField = false;
        },
        async loadTableHeader() {
            var vm = this;
            vm.isLoading = true;
            const param = 'submodule=CRM_LEADS&batchid=""';
            await DataService.GetContactTableColumn(param).then((response) => {
                vm.isLoading = false;
                if (response.data && response.data.length > 0) {
                    vm.tableColumns = response.data.sort((a, b) => (a.is_Required ? -1 : 1));
                } else {
                    vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", vm.$t('Alert'));
                }
            }).catch(() => {
                vm.isLoading = false;
                vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", vm.$t('Alert'));
            });
        },
    },

}
</script>
<style scoped>
.border-red {
    border: 2px solid red !important;
}
</style>