<template>
    <div>
        <loader :is-visible="isLoading"></loader>
        <tg-list :IsShowAction="false" ModuleName="CRM" SubModuleCode="CRM_LEADS" IdentityColumn="row_id"
            :listType="['List']" :HeaderText="$t('Leads')" :ListData="ListData" ref="tgList" :HeaderData="Headers"
            :HeaderButtons="false" :TotalRecords="TotalRecords" :IsSearchFieldsOnTop="false" :SearchFields="false"
            :widgets="[]" :RenderRowActionMethod="renderActions" :ListDataCallBackFunction="FetchData" :LegendArray="[]"
            :IsFilterApplied="searchCondition ? true : false" :SortExp="SortExp" :SortBy="SortBy"
            :CurrentPageNumber="PageNumber" v-on:LeftsearchButtonClick="leftCommonSearch"
            v-on:PagerButtonClick="pagerMethod" :NorecordfoundText="$t('NoRecordfound')"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:ActionButtonClick="actionButtonClick"
            v-on:SortdataButtonClick="sortdata" :showCheckBox="false">
        </tg-list>

        <div class="col-12 mt-3 p-0">
            <div class="row flex-row-reverse">
                <div class="col-lg-6 text-right">
                    <a href="javascript:void(0);" @click="$emit('backToValidation')" :title="$t('Back')"
                        :class="{ 'btn btn-secondary my-2 mr-2': true }">
                        <em class="fa fa-angle-double-left mr-2" aria-hidden="true"></em> {{ $t('Back') }}
                    </a>
                    <a href="javascript:void(0);" @click="$emit('next')" :title="$t('Next')" :class="{'btn btn-primary my-2 mr-2':true}">
                        {{$t('Next')}} <em class="fa fa-angle-double-right mr-2" aria-hidden="true"></em> 
                    </a>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import DataService from '../../services/DataService';

export default {
    props: {
        batchId: {
            type: String,
            required: true
        },
        IsAction:{
            type: String,
            required: true
        }
    },
    data: function () {
        return {
            SortExp: '',
            SortBy: '',
            isLoading: false,
            CompanyId: null,
            loggedInUserId: null,
            ListData: [],
            Headers: [],
            TotalRecords: 0,
            PageNumber: 1,
            searchCondition: ''
        }
    },
    created: function () {

        this.CompanyId = this.GetUserInfo.CompanyId;
        this.loggedInUserId = this.GetUserInfo.ID;
        this.FetchData();
    },

    methods: {
        sortdata() { },
        pagerMethod() { },
        leftCommonSearch() { },
        renderActions() { },
        listheaderbuttons() { },
        BackToList() { },
        commonHeaderButtonClick() { },
        actionButtonClick() { },
        HeaderButtonClick() { },
        ActionButtonClick() { },

        FetchData: function () {
            var vm = this;
            var param = `BatchId=${vm.batchId}`;
            DataService.ImportleadNew(param)
                .then(response => {
                    if (response.data != null) {
                        response.data.schema.forEach((element, index) => {
                            var Obj = {
                                COLUMN_NAME: element.COLUMN_NAME,
                                DATA_TYPE: "string",
                                SORTABLE: false,
                                VISIBLE: true,
                                DISPLAY_NAME: vm.$t(element.DISPLAY_NAME,element.COLUMN_NAME),
                                DISPLAY_ORDER: index + 1,
                            }
                            vm.Headers.push(Obj);
                        });
                        if (response.data.data.length > 0) {

                            vm.ListData = response.data.data;
                            
                            vm.ListData = response.data.data.map(item => {
                                if (item.lead_owner_id_lookup == null || item.lead_owner_id_lookup == undefined) {
                                    item.lead_owner_id_lookup = "N/A";
                                }
                                return item;
                            });
                        }
                    }
                })
            vm.isLoading = false;
        },
    }
};
</script>
