<template>
    <section>
        <div class="row">
            <div class="col-lg-12 mb-3">
                <div class="heading-border mt-2">
                    <h5 class="h5"><span>{{ $t('TotalRecordsProcessed') }} {{ TotalProcessedRecords }} </span></h5>
                </div>
            </div>
        </div>
        <!-- <div class="responsive-tabs-container accordion-xs accordion-sm">
            <ul class="nav nav-tabs all-tabs responsive-tabs tabnumbercontrol">
                <li class="nav-item active">
                    <a v-on:click="onChangeTab('unmatched')" style="cursor:pointer;" class="nav-link active"  href="#tabs-1" id="BillingInformation" data-toggle="tab" title="" data-toggle-tooltip="tooltip" data-original-title="Account Information">
                        <span class="tab-no mr-1"></span>Unmatched Records (4)
                    </a>
                </li>
                <li class="nav-item">
                    <a v-on:click="onChangeTab('error')" class="nav-link"  id="TALYGEN_account" data-toggle="tab" href="#tabs-1" title="" data-toggle-tooltip="tooltip" data-original-title="TALYGEN Account">
                        <span class="tab-no  mr-1"></span>Errors (4)
                    </a>
                </li>
            </ul>
        </div> -->

        <tg-list :isShowHeaderText="false" :IsShowAction="true" ModuleName="CRM" :SubModuleCode="subModuleCode"
            IdentityColumn="id" :listType="['List']" :ListData="ListData" ref="tgList" :HeaderData="Headers"
            :HeaderButtons="false" :TotalRecords="TotalRecords" :SearchFields="leftSearchFields"
            :IsSearchFieldsOnTop="true" SearchPosition="top" :widgets="[]" :RenderRowActionMethod="renderActions"
            :ListDataCallBackFunction="FetchData" :LegendArray="[]" :IsFilterApplied="false" :SortExp="SortExp"
            :SortBy="SortBy" :CurrentPageNumber="PageNumber" v-on:LeftsearchButtonClick="leftCommonSearch"
            v-on:PagerButtonClick="pagerMethod" :NorecordfoundText="$t('NoRecordfound')"
            v-on:HeaderButtonClick="commonHeaderButtonClick" v-on:ActionButtonClick="actionButtonClick"
            v-on:SortdataButtonClick="sortdata" :showCheckBox="false">
            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME == 'field_name'">
                    <span>{{ $t(data.row[data.column.COLUMN_NAME]) }}</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'error_type'">
                    <span class="text-danger font-weight-bold">{{ data.row[data.column.COLUMN_NAME] }}</span>
                </template>
            </template>
        </tg-list>
        <modalExcelBatchErrorFix v-if="isShowBatchError" @close="isShowBatchError = false" :batchId="batchId"
            :customFieldId="customFieldId" :customFieldName="customFieldName"
            :totalProcessedRecords="TotalProcessedRecords" :subModuleCode="subModuleCode"></modalExcelBatchErrorFix>

        <div class="clearfix"></div>
        <div class="col-12 mt-3 p-0" v-if="callFrom == 'preview'">
            <div class="row flex-row-reverse">
                <div class="col-lg-6 text-right">
                    <a href="javascript:void(0);" @click="$emit('back')" :title="$t('Back')"
                        :class="{ 'btn btn-secondary my-2 mr-2': true }">
                        <em class="fa fa-angle-double-left mr-2" aria-hidden="true"></em> {{ $t('Back') }}
                    </a>
                    <a href="javascript:void(0);" @click="$emit('next')" :title="$t('Next')"
                        :class="{ 'btn btn-primary my-2 mr-2': true }">
                        {{ $t('Next') }} <em class="fa fa-angle-double-right mr-2" aria-hidden="true"></em>
                    </a>
                </div>
            </div>
        </div>
        <div class="col-12 mt-3 p-0" v-else>
            <div class="row flex-row-reverse" v-if="notImportedRecords > 0">
                <div class="col-lg-6 text-right">
                    <a href="javascript:void(0);" @click="saveNotImported" :title="$t('Save')"
                        :class="{ 'btn btn-success my-2 mr-2': true }">
                        <em class="fa fa-save mr-2" aria-hidden="true"></em> Import Error Fixed Records
                        ({{ notImportedRecords
                        }})
                    </a>
                </div>
            </div>
        </div>
    </section>
</template>

<script>
import DataService from '../../services/DataService';
import modalExcelBatchErrorFix from './Modal/modalExcelBatchErrorFix.vue';

export default {
    props: {
        batchId: {
            type: String
        },
        subModuleCode: {
            type: String
        },
        callFrom: {
            type: String
        },
    },
    components: {
        modalExcelBatchErrorFix,
    },
    data() {
        return {

            isLoading: false,
            ListData: [],
            TotalRecords: 0,
            HeadersUnmatched: [
                {
                    COLUMN_NAME: 'name',
                    DATA_TYPE: "string",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('Column'),
                    DISPLAY_ORDER: 1,
                },
                {
                    COLUMN_NAME: 'value',
                    DATA_TYPE: "string",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('PreviewInformation'),
                    DISPLAY_ORDER: 2,
                },
                {
                    COLUMN_NAME: 'status',
                    DATA_TYPE: "string",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('Status'),
                    DISPLAY_ORDER: 3,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    COLUMN_NAME: 'field_type',
                    DATA_TYPE: "string",
                    SORTABLE: false,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('Fields'),
                    DISPLAY_ORDER: 4,
                    settings: {
                        isInSlot: true
                    }
                },
            ],
            Headers: [
                {
                    COLUMN_NAME: 'field_name',
                    DATA_TYPE: "string",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('Column'),
                    DISPLAY_ORDER: 1,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    COLUMN_NAME: 'error_type',
                    DATA_TYPE: "string",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('ErrorType'),
                    DISPLAY_ORDER: 2,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    COLUMN_NAME: 'counts',
                    DATA_TYPE: "string",
                    SORTABLE: true,
                    VISIBLE: true,
                    DISPLAY_NAME: this.$t('ErrorCount'),
                    DISPLAY_ORDER: 3
                },
            ],
            leftSearchFields: [{
                fieldName: 'Search',
                fieldType: "text",
                fieldSearchConditionName: [''],
                paramName: "search",
                isSearch: true,
                value: "",
                listOptions: []
            }],
            listActions: [{
                title: 'View',
                callbackfunction: 'getAndFixError',
                href: 'javascript:void(0)',
                icon: 'fa fa-eye action-icon',
                additionalSpan: ''
            },],
            SortExp: '',
            SortBy: '',
            PageNumber: 1,
            PageSize: 10,
            searchCondition: '',
            TotalProcessedRecords: 0,
            isShowBatchError: false,
            customFieldId: '',
            customFieldName: '',
            notImportedRecords: 0,

        }
    },
    async created() {
        await this.FetchData();
    },
    methods: {
        async FetchData() {
            var vm = this;
            vm.isLoading = true;
            let params = `batchId=${vm.batchId}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&pageNum=${vm.PageNumber}&pageSize=${vm.PageSize}&searchCondition=${vm.searchCondition}`;
            await DataService.GetImportedRecordsError(params).then((response) => {
                if (response.data && response.data.data) {
                    vm.ListData = JSON.parse(response.data.data);
                    vm.TotalRecords = vm.ListData[0].total_records;
                    vm.TotalProcessedRecords = response.data.total_records;
                    vm.notImportedRecords = response.data.not_imported_records;
                } else {
                    vm.TotalRecords = 0;
                    vm.ListData = [];
                    vm.TotalProcessedRecords = response.data.total_records;
                    vm.notImportedRecords = response.data.not_imported_records;
                }
                vm.isLoading = false;
            }).catch((error) => {
                vm.isLoading = false;
                console.error(error);
            });
        },
        // onChangeTab(tabName){
        //     if(tabName == 'unmatched'){
        //         this.Headers = this.HeadersUnmatched;
        //     }else if(tabName == 'error'){
        //         this.Headers = this.HeadersErrorTab;
        //     }
        //     this.FetchData(this.batchId);
        // },
        sortdata: function (s) {
            var SortDir = "sort tb_headerSortDown";
            this.SortBy = s;
            if (s === this.SortBy) {
                if (this.SortExp == "") {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
                else if (this.SortExp == "ASC") {
                    this.SortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                }
                else {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }
            this.FetchData();
            $("#" + s + '  span:first-child').attr("class", SortDir);
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            if (value.searchCondition) {
                let str = value.searchConditionJson;
                let result = str.split('=')[1];
                this.searchCondition = result;
            }
            else {
                this.searchCondition = "";
            }
            this.FetchData();
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                switch (action.title) {
                    case 'View':
                        action.isVisible = true;
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        commonHeaderButtonClick(event) { },
        actionButtonClick: function (callbackfunction, item, index, event) {
            var vm = this;
            switch (callbackfunction) {
                case 'getAndFixError':
                    vm.getAndFixError(item);
                    break;
            }
        },
        getAndFixError(row) {
            this.customFieldId = row.custom_field_id;
            this.isShowBatchError = true;
            this.customFieldName = this.$t(row.field_name);
        },
        async saveNotImported() {
            var vueObj = this;
            vueObj.isLoading = true;
            var param = `BatchId=${vueObj.batchId}&ModuleCode=CRM&SubModuleCode=CRM_LEADS&IsAction=Add&UpdateField= `;
            await DataService.SaveImportleadData(param).then(async function (response) {
                if (response.data == "ADD DATA SUCCESSFULLY!") {
                    vueObj.ShowAlert(vueObj.$t('AddedSuccess', [vueObj.$t('Lead')]), 'success', true, vueObj.$t("Alert"));
                    await vueObj.FetchData();
                    await vueObj.$parent.$parent.FetchData();
                    await vueObj.$parent.$emit('close');
                    vueObj.isLoading = false;
                }
                else {
                    vueObj.ShowAlert(vueObj.$t('AddedError', [vueObj.$t('Lead')]), 'warning', true, vueObj.$t("Alert"));
                }
                vueObj.isLoading = false;
            });
        }
    }
}
</script>