<template>
    <div class="col-lg-12 float-left p-0">
        <div class="col-lg-12  mb-4 border" v-if="!isShowBatchList">
            <section>
                <div class="col-lg-12 mb-3 p-0 mt-4">
                    <div class="heading-border mt-2">
                        <h5 class="h5"><span>{{ $t('UploadFile') }}</span>
                            <div class="form-group d-flex float-right mr-4">
                                <label class="mr-3 pt-1">{{ $t('Download') }} {{ $t('SampleFile') }}:</label>
                                <div class="d-flex align-items-center font-16">
                                    <a href="/Content/files/LeadImportSampleFile.xlsx" checkprivilege="no"
                                        class="text-dark" download>
                                        <img src="/Content/images/excel-icon.png" alt="" class="mr-2" />{{ $t('Lead') }}
                                        <em class="fa fa-download ml-2 text-dark"></em>
                                    </a>
                                </div>
                            </div>
                        </h5>
                    </div>
                </div>

                <dynamic-form lang="en" ref="AddTeamForm" :buttons="buttons" :schema="FormSchema"></dynamic-form>
                <div class="col-12 mt-3 p-0">
                    <div class="row flex-row-reverse">
                        <div class="col-lg-6 text-right">
                            <a href="javascript:void(0);" id="uploadfile" :title="$t('ImportFromExcelFile')"
                                @click="ChooseLeadLayout" :class="{ 'btn btn-info my-2 mr-2': true }">
                                <em class="fa fa-file-excel-o mr-2" aria-hidden="true"></em>
                                {{ $t('ImportFromExcelFile') }}
                            </a>
                            <a href="/CRM/ImportLeads" :title="$t('Cancel')" class="btn btn-danger mr-2"><em
                                    class="fa fa-times mr-2 "></em>{{ $t('Cancel') }}</a>
                            <RouterLink to="/CRM/Index" :title="$t('BacktoList')" class="btn btn-secondary my-2">
                                <em class="fa fa-angle-double-left pr-2"></em> {{ $t('BacktoList') }}
                            </RouterLink>
                        </div>
                        <div class="col-lg-6">
                            <div class="py-2">
                                <span class="text-danger">
                                    <small class="text-danger">{{ $t('MandatoryString') }}</small>
                                </span>
                            </div>
                        </div>
                    </div>
                </div>
            </section>
        </div>
        <ImportedBatchList v-if="isShowBatchList" subModuleCode="CRM_LEADS"></ImportedBatchList>
        <ChooseLeadLayout v-if="IsLeadLayoutShow" @callImport="callImport"></ChooseLeadLayout>
    </div>
</template>
<script>
import ChooseLeadLayout from './Modal/ChooseLeadLayout.vue';
import ImportedBatchList from './ImportedBatchList.vue';

export default {
    components: {
        ChooseLeadLayout,
        ImportedBatchList
    },
    data() {
        return {
            isShowBatchList: true,
            IsLeadLayoutShow: false,
            selectedFile: null,  // To store the selected file
            excelFileName: '',
            file: null,
            FormSchema: [
                {
                    layoutType: "single",
                    //group_name: 'Add User Scroll',
                    Data: [
                        {
                            astype: "FileField",
                            //label: "Avatar",
                            name: "avatar",
                            value: "",
                            placeholder: "Enter Avatar",
                            config: {
                                maxSize: 5,
                                onChange: this.handleFileUpload,
                                accept: [
                                    {
                                        fileType: 'xlsx', // .xlsx
                                        iconClass: 'fa fa-file-excel-o'
                                    },
                                    {
                                        fileType: 'xls', // .xls
                                        iconClass: 'fa fa-file-excel-o'
                                    },
                                    {
                                        fileType: 'csv', // .xls
                                        iconClass: 'fa fa-file-excel-o'
                                    }
                                ],

                            },

                        }
                    ]
                }
            ],
            buttons: [
                // {
                //     type: "submit",
                //     class: "btn btn-success",
                //     text: "<i class='fa fa-upload pr-2'></i>Upload",
                //     //onClick: this.SaveTeamMemberData
                // }
            ],
        }
    },
    methods: {
        handleFileUpload(event) {
            var vm = this;
            vm.selectedFile = event.target.files[0]; // Store the selected file
            vm.file = event.target.files[0];
            vm.excelFileName = vm.file ? vm.file.name : '';
        },
        ChooseLeadLayout() {
            var vm = this;
            if (!vm.selectedFile) {
                vm.ShowAlert(vm.$t('PleaseUploadExcelFile'), "warning", true, vm.$t("Alert"));
                return;
            }
            vm.IsLeadLayoutShow = true;
        },
        callImport(event, Field) {
            this.$emit('ImportData', this.selectedFile, this.file, this.excelFileName, event, Field)
        }
    },
}
</script>